def minCostClimbingStairs(cost):
    n = len(cost)
    # Compute minimum cost to reach each step in-place
    for i in range(2, n):
        cost[i] += min(cost[i - 1], cost[i - 2])
    return min(cost[n - 1], cost[n - 2])

