    for (int j = 0; j <= n; ++j) dp[m][j] = n - j;

    for (int i = m - 1; i >= 0; --i) {
        for (int j = n - 1; j >= 0; --j) {
            if (word1[i] == word2[j]) {
                dp[i][j] = dp[i + 1][j + 1];
            } else {
                dp[i][j] = 1 + min({dp[i + 1][j],      // Delete
                                    dp[i][j + 1],      // Insert
                                    dp[i + 1][j + 1]}); // Replace
            }
        }
    }
    return dp[0][0];
}

