def isMatch(s, p):
    memo = {}

    def dfs(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if j == len(p):
            return i == len(s)

        match = i < len(s) and (s[i] == p[j] or p[j] == '.')

        if j + 1 < len(p) and p[j + 1] == '*':
            # Choice 1: Don't use '*' (skip pattern char and '*')
            # Choice 2: Use '*' (if current char matches, advance string pointer)
            res = dfs(i, j + 2) or (match and dfs(i + 1, j))
        else:
            res = match and dfs(i + 1, j + 1)

        memo[(i, j)] = res
        return res

    return dfs(0, 0)

